-- ============================================================
-- Member Groups & Demo Members
-- ============================================================

-- Member groups (teams/squads)
create table if not exists member_groups (
  id          uuid primary key default uuid_generate_v4(),
  org_id      uuid not null references organisations(id) on delete cascade,
  name        text not null,
  color       text,
  sort_order  integer not null default 0,
  created_at  timestamptz not null default now()
);

create index if not exists member_groups_org_id_idx on member_groups(org_id);

-- Many-to-many: persons <-> member_groups
create table if not exists member_group_memberships (
  group_id    uuid not null references member_groups(id) on delete cascade,
  person_id   uuid not null references persons(id) on delete cascade,
  primary key (group_id, person_id)
);

create index if not exists mgm_group_id_idx on member_group_memberships(group_id);
create index if not exists mgm_person_id_idx on member_group_memberships(person_id);

-- Add attendance columns to invitees if not already present
alter table invitees add column if not exists attended      boolean not null default false;
alter table invitees add column if not exists signed_out    boolean not null default false;
alter table invitees add column if not exists ticket_type   text;
alter table invitees add column if not exists fee_amount    numeric(10,2);
alter table invitees add column if not exists paid_at       timestamptz;

